model.metadata:
CREATE VIEW v_c2_01 AS
  SELECT nik, nama
  FROM bansos_db.master_pendudukk;

CREATE VIEW v_c2_02 AS
  SELECT eligibility_id, nik
  FROM bansos_db.eligibilitty;

CREATE VIEW v_c2_03 AS
  SELECT program_id, nama_program
  FROM bansos_db.master_program_bansoss;

CREATE VIEW v_c2_04 AS
  SELECT penerima_id, nik
  FROM bansos_db.master_penerimaa;

CREATE VIEW v_c2_05 AS
  SELECT no_kk, alamat
  FROM bansos_db.master_keluraga;

CREATE VIEW v_c2_unknown AS
  SELECT nik, nama
  FROM bansos_db.xyz_totally_wrong_table;

CREATE VIEW v_c2_ok AS
  SELECT nik, nama
  FROM bansos_db.master_penduduk;
